import{_ as l,o as e,c as a,ai as i}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"数据库工具","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/database-tools.md","filePath":"open-source/database-tools.md"}'),t={name:"open-source/database-tools.md"};function o(s,r,h,n,u,b){return e(),a("div",null,[...r[0]||(r[0]=[i('<h1 id="数据库工具" tabindex="-1">数据库工具 <a class="header-anchor" href="#数据库工具" aria-label="Permalink to “数据库工具”">​</a></h1><p>本页面精选了数据库相关的开源工具，包括管理工具、监控工具、迁移工具等。</p><h2 id="mysql-工具" tabindex="-1">MySQL 工具 <a class="header-anchor" href="#mysql-工具" aria-label="Permalink to “MySQL 工具”">​</a></h2><h3 id="管理工具" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><p><strong>phpMyAdmin</strong>：Web-based MySQL管理工具</p><ul><li>GitHub: <a href="https://github.com/phpmyadmin/phpmyadmin" target="_blank" rel="noreferrer">https://github.com/phpmyadmin/phpmyadmin</a></li><li>功能: Web界面、SQL查询、数据库管理</li></ul></li><li><p><strong>Adminer</strong>：轻量级数据库管理工具</p><ul><li>GitHub: <a href="https://github.com/vrana/adminer" target="_blank" rel="noreferrer">https://github.com/vrana/adminer</a></li><li>特点: 单文件、支持多种数据库</li></ul></li><li><p><strong>MySQL Workbench</strong>：官方GUI工具</p><ul><li>GitHub: <a href="https://github.com/mysql/mysql-workbench" target="_blank" rel="noreferrer">https://github.com/mysql/mysql-workbench</a></li><li>功能: 数据库设计、SQL开发、服务器管理</li></ul></li></ul><h3 id="命令行工具" tabindex="-1">命令行工具 <a class="header-anchor" href="#命令行工具" aria-label="Permalink to “命令行工具”">​</a></h3><ul><li><p><strong>mycli</strong>：MySQL命令行客户端</p><ul><li>GitHub: <a href="https://github.com/dbcli/mycli" target="_blank" rel="noreferrer">https://github.com/dbcli/mycli</a></li><li>特点: 自动补全、语法高亮</li></ul></li><li><p><strong>Percona Toolkit</strong>：MySQL工具集</p><ul><li>GitHub: <a href="https://github.com/percona/percona-toolkit" target="_blank" rel="noreferrer">https://github.com/percona/percona-toolkit</a></li><li>功能: 性能分析、数据恢复</li></ul></li></ul><h3 id="监控工具" tabindex="-1">监控工具 <a class="header-anchor" href="#监控工具" aria-label="Permalink to “监控工具”">​</a></h3><ul><li><p><strong>Prometheus MySQL Exporter</strong>：MySQL监控导出器</p><ul><li>GitHub: <a href="https://github.com/prometheus/mysqld_exporter" target="_blank" rel="noreferrer">https://github.com/prometheus/mysqld_exporter</a></li><li>功能: 指标收集、Prometheus集成</li></ul></li><li><p><strong>Percona Monitoring and Management</strong>：数据库监控平台</p><ul><li>GitHub: <a href="https://github.com/percona/pmm" target="_blank" rel="noreferrer">https://github.com/percona/pmm</a></li><li>功能: 性能监控、查询分析</li></ul></li></ul><h2 id="redis-工具" tabindex="-1">Redis 工具 <a class="header-anchor" href="#redis-工具" aria-label="Permalink to “Redis 工具”">​</a></h2><h3 id="管理工具-1" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具-1" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><p><strong>RedisInsight</strong>：Redis可视化管理工具</p><ul><li>GitHub: <a href="https://github.com/RedisInsight/RedisInsight" target="_blank" rel="noreferrer">https://github.com/RedisInsight/RedisInsight</a></li><li>功能: 数据浏览、性能监控、CLI</li></ul></li><li><p><strong>Redis Commander</strong>：Web-based Redis管理</p><ul><li>GitHub: <a href="https://github.com/joeferner/redis-commander" target="_blank" rel="noreferrer">https://github.com/joeferner/redis-commander</a></li><li>功能: 数据查看、键操作</li></ul></li></ul><h3 id="命令行工具-1" tabindex="-1">命令行工具 <a class="header-anchor" href="#命令行工具-1" aria-label="Permalink to “命令行工具”">​</a></h3><ul><li><strong>iredis</strong>：Redis命令行客户端 <ul><li>GitHub: <a href="https://github.com/laixintao/iredis" target="_blank" rel="noreferrer">https://github.com/laixintao/iredis</a></li><li>特点: 自动补全、语法高亮</li></ul></li></ul><h3 id="集群工具" tabindex="-1">集群工具 <a class="header-anchor" href="#集群工具" aria-label="Permalink to “集群工具”">​</a></h3><ul><li><strong>Redis Cluster Proxy</strong>：Redis集群代理 <ul><li>GitHub: <a href="https://github.com/RedisLabs/redis-cluster-proxy" target="_blank" rel="noreferrer">https://github.com/RedisLabs/redis-cluster-proxy</a></li><li>功能: 集群负载均衡</li></ul></li></ul><h2 id="mongodb-工具" tabindex="-1">MongoDB 工具 <a class="header-anchor" href="#mongodb-工具" aria-label="Permalink to “MongoDB 工具”">​</a></h2><h3 id="管理工具-2" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具-2" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><p><strong>MongoDB Compass</strong>：官方GUI工具</p><ul><li>GitHub: <a href="https://github.com/mongodb-js/compass" target="_blank" rel="noreferrer">https://github.com/mongodb-js/compass</a></li><li>功能: 数据浏览、查询构建、性能分析</li></ul></li><li><p><strong>Studio 3T</strong>：MongoDB IDE</p><ul><li>GitHub: <a href="https://github.com/Studio3T/robomongo" target="_blank" rel="noreferrer">https://github.com/Studio3T/robomongo</a></li><li>功能: 查询构建、可视化编辑</li></ul></li><li><p><strong>NoSQLBooster</strong>：MongoDB GUI工具</p><ul><li>GitHub: <a href="https://github.com/nosqlbooster/nosqlbooster" target="_blank" rel="noreferrer">https://github.com/nosqlbooster/nosqlbooster</a></li><li>功能: SQL查询、导入导出</li></ul></li></ul><h3 id="命令行工具-2" tabindex="-1">命令行工具 <a class="header-anchor" href="#命令行工具-2" aria-label="Permalink to “命令行工具”">​</a></h3><ul><li><strong>mongo-hacker</strong>：MongoDB shell增强 <ul><li>GitHub: <a href="https://github.com/TylerBrock/mongo-hacker" target="_blank" rel="noreferrer">https://github.com/TylerBrock/mongo-hacker</a></li><li>功能: 语法高亮、自动补全</li></ul></li></ul><h2 id="postgresql-工具" tabindex="-1">PostgreSQL 工具 <a class="header-anchor" href="#postgresql-工具" aria-label="Permalink to “PostgreSQL 工具”">​</a></h2><h3 id="管理工具-3" tabindex="-1">管理工具 <a class="header-anchor" href="#管理工具-3" aria-label="Permalink to “管理工具”">​</a></h3><ul><li><p><strong>pgAdmin</strong>：PostgreSQL管理平台</p><ul><li>GitHub: <a href="https://github.com/pgadmin-org/pgadmin4" target="_blank" rel="noreferrer">https://github.com/pgadmin-org/pgadmin4</a></li><li>功能: 数据库管理、查询工具</li></ul></li><li><p><strong>DBeaver</strong>：通用数据库工具</p><ul><li>GitHub: <a href="https://github.com/dbeaver/dbeaver" target="_blank" rel="noreferrer">https://github.com/dbeaver/dbeaver</a></li><li>支持: PostgreSQL、MySQL等多种数据库</li></ul></li></ul><h3 id="扩展工具" tabindex="-1">扩展工具 <a class="header-anchor" href="#扩展工具" aria-label="Permalink to “扩展工具”">​</a></h3><ul><li><strong>PostGIS</strong>：PostgreSQL地理空间扩展 <ul><li>GitHub: <a href="https://github.com/postgis/postgis" target="_blank" rel="noreferrer">https://github.com/postgis/postgis</a></li><li>功能: 地理数据处理、空间查询</li></ul></li></ul><h2 id="数据库迁移工具" tabindex="-1">数据库迁移工具 <a class="header-anchor" href="#数据库迁移工具" aria-label="Permalink to “数据库迁移工具”">​</a></h2><h3 id="通用迁移" tabindex="-1">通用迁移 <a class="header-anchor" href="#通用迁移" aria-label="Permalink to “通用迁移”">​</a></h3><ul><li><p><strong>Flyway</strong>：数据库版本控制</p><ul><li>GitHub: <a href="https://github.com/flyway/flyway" target="_blank" rel="noreferrer">https://github.com/flyway/flyway</a></li><li>功能: 版本化迁移、多种数据库支持</li></ul></li><li><p><strong>Liquibase</strong>：数据库重构工具</p><ul><li>GitHub: <a href="https://github.com/liquibase/liquibase" target="_blank" rel="noreferrer">https://github.com/liquibase/liquibase</a></li><li>功能: 变更日志、回滚支持</li></ul></li></ul><h3 id="数据迁移" tabindex="-1">数据迁移 <a class="header-anchor" href="#数据迁移" aria-label="Permalink to “数据迁移”">​</a></h3><ul><li><strong>pgloader</strong>：PostgreSQL数据加载器 <ul><li>GitHub: <a href="https://github.com/dimitri/pgloader" target="_blank" rel="noreferrer">https://github.com/dimitri/pgloader</a></li><li>功能: 数据迁移、格式转换</li></ul></li></ul><h2 id="数据库备份工具" tabindex="-1">数据库备份工具 <a class="header-anchor" href="#数据库备份工具" aria-label="Permalink to “数据库备份工具”">​</a></h2><ul><li><p><strong>mysqldump</strong>：MySQL官方备份工具</p><ul><li>功能: 逻辑备份、恢复</li></ul></li><li><p><strong>pg_dump</strong>：PostgreSQL备份工具</p><ul><li>功能: 数据库备份、恢复</li></ul></li><li><p><strong>mongodump</strong>：MongoDB备份工具</p><ul><li>功能: BSON格式备份</li></ul></li></ul><h2 id="性能分析工具" tabindex="-1">性能分析工具 <a class="header-anchor" href="#性能分析工具" aria-label="Permalink to “性能分析工具”">​</a></h2><h3 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to “MySQL”">​</a></h3><ul><li><p><strong>MySQLTuner</strong>：MySQL性能调优脚本</p><ul><li>GitHub: <a href="https://github.com/major/MySQLTuner-perl" target="_blank" rel="noreferrer">https://github.com/major/MySQLTuner-perl</a></li><li>功能: 配置建议、性能分析</li></ul></li><li><p><strong>pt-query-digest</strong>：MySQL查询分析</p><ul><li>GitHub: <a href="https://github.com/percona/percona-toolkit" target="_blank" rel="noreferrer">https://github.com/percona/percona-toolkit</a></li><li>功能: 慢查询分析</li></ul></li></ul><h3 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to “Redis”">​</a></h3><ul><li><strong>redis-benchmark</strong>：Redis性能测试 <ul><li>功能: 基准测试、性能评估</li></ul></li></ul><h3 id="通用工具" tabindex="-1">通用工具 <a class="header-anchor" href="#通用工具" aria-label="Permalink to “通用工具”">​</a></h3><ul><li><strong>sysbench</strong>：多线程基准测试工具 <ul><li>GitHub: <a href="https://github.com/akopytov/sysbench" target="_blank" rel="noreferrer">https://github.com/akopytov/sysbench</a></li><li>功能: CPU、内存、I/O、数据库测试</li></ul></li></ul><h2 id="数据库代理" tabindex="-1">数据库代理 <a class="header-anchor" href="#数据库代理" aria-label="Permalink to “数据库代理”">​</a></h2><ul><li><p><strong>ProxySQL</strong>：MySQL代理</p><ul><li>GitHub: <a href="https://github.com/sysown/proxysql" target="_blank" rel="noreferrer">https://github.com/sysown/proxysql</a></li><li>功能: 读写分离、连接池、查询路由</li></ul></li><li><p><strong>MaxScale</strong>：数据库代理</p><ul><li>GitHub: <a href="https://github.com/mariadb-corporation/MaxScale" target="_blank" rel="noreferrer">https://github.com/mariadb-corporation/MaxScale</a></li><li>支持: MySQL、MariaDB</li></ul></li></ul><h2 id="数据库中间件" tabindex="-1">数据库中间件 <a class="header-anchor" href="#数据库中间件" aria-label="Permalink to “数据库中间件”">​</a></h2><ul><li><p><strong>ShardingSphere</strong>：分布式数据库中间件</p><ul><li>GitHub: <a href="https://github.com/apache/shardingsphere" target="_blank" rel="noreferrer">https://github.com/apache/shardingsphere</a></li><li>功能: 数据分片、读写分离</li></ul></li><li><p><strong>MyCat</strong>：MySQL分库分表中间件</p><ul><li>GitHub: <a href="https://github.com/MyCATApache/Mycat-Server" target="_blank" rel="noreferrer">https://github.com/MyCATApache/Mycat-Server</a></li><li>功能: 分库分表、读写分离</li></ul></li></ul><h2 id="数据库连接池" tabindex="-1">数据库连接池 <a class="header-anchor" href="#数据库连接池" aria-label="Permalink to “数据库连接池”">​</a></h2><ul><li><p><strong>HikariCP</strong>：高性能JDBC连接池</p><ul><li>GitHub: <a href="https://github.com/brettwooldridge/HikariCP" target="_blank" rel="noreferrer">https://github.com/brettwooldridge/HikariCP</a></li><li>特点: 快速、轻量级</li></ul></li><li><p><strong>Druid</strong>：阿里数据库连接池</p><ul><li>GitHub: <a href="https://github.com/alibaba/druid" target="_blank" rel="noreferrer">https://github.com/alibaba/druid</a></li><li>功能: 监控、SQL解析</li></ul></li></ul>',46)])])}const d=l(t,[["render",o]]);export{p as __pageData,d as default};
